import React, {useEffect} from "react";
import SkillsCard from "../../component/lil-component/SkillsCard";
import {
  Bootstrap,
  Codei,
  CssNat,
  Dart,
  Flutter,
  Html,
  Javascript,
  Mysql,
  Php,
  ReactJs,
  TailCss,
} from "../../svg";


const Skills = () => {

  return (
    <div
      id="blogPage"
      className="flex h-full flex-col w-full justify-start mt-16 items-start overflow-scroll">
      <p className="mt-4 text-3xl">My Basic Skills and Knowledge</p>
      <div className="flex flex-col mt-4">
        <div className="mb-8">
          <p>Programming Language</p>
          <div className="flex mt-2 flex-wrap">
            <SkillsCard img={Javascript} name={"Javascript"}/>
            <SkillsCard img={Php} name={"PHP"}/>
            <SkillsCard img={Dart} name={"Dart"}/>
          </div>
        </div>
        <div className="mb-8">
          <p>Frontend</p>
          <div className="flex mt-2 flex-wrap">
            <SkillsCard img={Html} name={"Html"}/>
            <SkillsCard img={CssNat} name={"CSS"}/>
            <SkillsCard img={TailCss} name={"TailwindCSS"}/>
            <SkillsCard img={Bootstrap} name={"Bootstrap"}/>
            <SkillsCard img={ReactJs} name={"ReactJS"}/>
          </div>
        </div>
        <div className="mb-8">
          <p>Backend</p>
          <div className="flex mt-2 flex-wrap">
            <SkillsCard img={Codei} name={"CodeIgniter"}/>
            <SkillsCard img={Mysql} name={"MySQL"}/>
          </div>
        </div>
        <div className="mb-8">
          <p>Mobile Apps</p>
          <div className="flex mt-2 flex-wrap">
            <SkillsCard img={ReactJs} name={"React Native"}/>
            <SkillsCard img={Flutter} name={"Flutter"}/>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Skills;
