import React from "react";
const SkillsCard = (props) => {
  return (
    <div data-aos="fade-up" className="max-h-40 w-36 rounded-md bg-newColor-dark dark:bg-primarycolor-dark shadow-md mr-2 mb-2">
      <div className="relative h-full p-8 flex items-center justify-center">
      <img className="mb-4" src={props.img} alt="" />
      <p className="absolute bottom-1 font-medium text-sm">{props.name}</p>
      </div>
    </div>
  );
};

export default SkillsCard;
