import React, { useEffect, useState } from "react";
import {
  DiAptana,
  DiCss3,
  DiDart,
  DiHtml5,
  DiJavascript1,
  DiPhp,
  DiReact,
} from "react-icons/di";

const ProjectCard = (props) => {
  const [thumbnail, setthumbnail] = useState(
    "https://i.ibb.co/BswzvkY/blank-front-page-slider-background-grey-new.jpg"
  );
  const [lang, setlang] = useState([]);

  useEffect(() => {
    fetch(props.language)
      .then((res) => res.json())
      .then((json) => {
        setlang(json);
      });

    props.thumbnail === null
      ? setthumbnail(thumbnail)
      : setthumbnail(props.thumbnail.split(" || ").pop());
  }, []);

  //icons
  const myFunc = (nams) => {
    let icons;
    switch (nams) {
      case "javascript":
        icons = <DiJavascript1 />;
        break;
      case "php":
        icons = <DiPhp />;
        break;
      case "dart":
        icons = <DiDart />;
        break;
      case "undefined":
        icons = <DiAptana />;
        break;
      case "css":
        icons = <DiCss3 />;
        break;
      case "html":
        icons = <DiHtml5 />;
        break;
      default:
        icons = <DiAptana />;
    }
    return icons;
  };

  const propertyNames = Object.keys(lang);

  return (
    <div className="mb-2 shadow-md rounded-lg bg-white dark:bg-primarycolor-dark">
      <img
        className="bg-cover rounded-lg"
        src={thumbnail}
        alt=""
      />
      <div className="flex flex-row justify-between px-4 py-1 items-center text-sm font-bold">
        <p>{props.name}</p>
        <div className="flex flex-row">
          {propertyNames.map((names, index) => {
            return (
              <div
                key={index}
                className="h-7 w-7 p-1 mr-1 rounded-full bg-newColor-light text-3xl flex items-center justify-center text-white"
              >
                {myFunc(names.toLowerCase())}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default ProjectCard;
