import React from "react";
import { Coveids } from "../../svg";
const VirusCard = (props) => {
  return (
    <div className="w-1/3 relative bg-white dark:bg-secondarycolor-dark rounded-md md:rounded-xl shadow-xl mx-1">
      <div className="flex flex-row md:p-4 justify-between p-2">
        <div className="flex flex-col md:flex-col justify-between">
          <p className="md:text-xl text-sm font-bold md:mb-4">{props.title}</p>
          <p className={`md:text-3xl text-md ${props.color} break-all`}>
            {props.case}
          </p>
        </div>
      </div>
      <img src={Coveids} className="w-0 md:w-1/4 absolute top-2 right-2" alt="" />
    </div>
  );
};

export default VirusCard;
