import React, { useState, useEffect } from "react";
import { useRouteMatch, Switch, Route } from "react-router-dom";
import ArticleList from "../component/ArticleList";
import useWindowDimension from "../hooks/useWindow";
import { Post } from "../svg";
import ContentBlog from "./blog/ContentBlog";

const BlogPage = () => {
  const [post, setpost] = useState([]);
  const [loading, setloading] = useState(true);
  let { url, path } = useRouteMatch();
  const screenSize = useWindowDimension();

  useEffect(() => {
    fetch(
      `https://www.googleapis.com/blogger/v3/blogs/1508988598239930546/posts?key=${process.env.REACT_APP_GOOGLE_API_KEY}`
    )
      .then((response) => response.json())
      .then((json) => {
        setpost(json);
        setloading(false);
      });
  }, []);

  return (
    <>
      {screenSize.width > 768 ? (
        <div
          id="blogPage"
          className=" relative flex-col flex h-full w-full bg-secondarycolor-light dark:bg-secondarycolor-dark md:pl-24 md:pr-8 md:py-4 text-primarycolor-light overflow-y-auto overflow-x-hidden md:w-2/3 md:h-full md:rounded-r-3xl"
        >
          <Switch>
            <Route path={`${path}/post/:id`}>
              <ContentBlog />
            </Route>
            <Route path={`${path}`}>
              <div className="flex h-full flex-col w-full justify-center items-center">
                <div>
                  <Post className="w-72 h-40 mb-8" />
                </div>
              </div>
            </Route>
          </Switch>
        </div>
      ) : (
        ""
      )}
      <ArticleList
        screenSize={screenSize}
        post={post.items}
        url={url}
        loading={loading}
      />
    </>
  );
};

export default BlogPage;
