import React, { useEffect, useState } from "react";
import { useParams } from "react-router";
import Spinner from "../../component/lil-component/Spinner";
import parse from "html-react-parser";

const DetailPost = () => {
  const [blogdet, setblogdet] = useState({});
  const [isloading, setloading] = useState(true);
  const params = useParams().id;
  

  useEffect(() => {
    
    getData(params);

    return()=>{
      setloading(true)
    }

  }, [params]);

  const getData = (s) => {
    fetch(
      `https://www.googleapis.com/blogger/v3/blogs/1508988598239930546/posts/${s}?key=AIzaSyAAVZYXPT8zFWG3am6XcZOpOjwcfxBFexk`
    )
      .then((res) => res.json())
      .then((json) => {
        setblogdet(json.content);
        setloading(false);
      }).catch((err)=> console.log(err));
  };

  console.log(params)

  return isloading ? (
    <Spinner />
  ) : (
    <div className="overflow-ellipsis font-normal font-sans p-4 mb-8 dark:text-white">
      {parse(blogdet, {htmlparser2:{xmlMode: true}})}
    </div>
  );
};

export default DetailPost;
