import React, { useEffect, useState } from "react";
import ProfileDesc from "./lil-component/ProfileDesc";
import ProjectCard from "./lil-component/ProjectCard";
import Spinner from "./lil-component/Spinner";
const Showcase = (props) => {
  //state
  const [owner, setowner] = useState([]);
  const [bio, setbio] = useState([]);
  //props
  const loading = props.loading;
  const repository = props.repository;
  //var

  useEffect(() => {
    fetch("https://api.github.com/users/riskidwi1711")
      .then((res) => res.json())
      .then((json) => {
        setowner(json);
        setbio(json.bio.split(" || "));
      });

    return () => {
      setowner([]);
      setbio([]);
    };
  }, []);
  return (
    <div
      id="showcase"
      className="flex flex-col flex-1 overflow-auto px-8 py-4 mb-16 md:mb-0 dark:text-white"
    >
      {!loading ? (
        <>
          <div className="flex lg:flex-row flex-col items-center justify-center">
            <div>
              <img
                className="md:h-16 md:w-16 h-32 w-32 bg-cover rounded-full lg:mr-4"
                src={owner.avatar_url}
              />
            </div>
            <ProfileDesc bio={bio} name={owner.name} />
          </div>
          <div className="mt-4">
            <p className="text-lg">My Project</p>
            <p className="text-sm font-medium mb-3">
              Some project i've been created
            </p>
            {repository.map((repo) => {
              return (
                <ProjectCard
                  key={repo.id}
                  name={repo.name}
                  thumbnail={repo.description}
                  language={repo.languages_url}
                />
              );
            })}
          </div>
        </>
      ) : (
        <Spinner />
      )}
    </div>
  );
};

export default Showcase;
