import React, { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import parse from "html-react-parser";
import Spinner from "../../component/lil-component/Spinner";
const ContentBlog = () => {
  let { id } = useParams();
  const [content, setcontent] = useState(" ");
  const [loading, setloading] = useState(true);
  useEffect(() => {
    getData(id);

    return()=>{
      setloading(true)
    }
  }, [id]);

  const getData = (s) => {
    fetch(
      `https://www.googleapis.com/blogger/v3/blogs/1508988598239930546/posts/${s}?key=AIzaSyAAVZYXPT8zFWG3am6XcZOpOjwcfxBFexk`
    )
      .then((res) => res.json())
      .then((json) => {
        setcontent(json.content);
        setloading(false);
      }).catch((err)=> console.log(err));
  };

  return loading ? (
    <Spinner />
  ) : (
    <div className="overflow-ellipsis font-normal font-sans dark:text-white">
      {parse(content, {htmlparser2:{xmlMode: true}})}
    </div>
  );
};

export default ContentBlog;
