import React, {useState, useEffect} from "react";
import {
  BrowserRouter as Router,
  useRouteMatch,
  Switch,
  Route,
  useParams,
  useHistory,
} from "react-router-dom";
import { NoMatch } from ".";
import Header from "../component/Header";
import Showcase from "../component/Showcase";
import { AboutMe, Sertificate, Skills } from "../pages/home";

const HomePage = () => {
  let match = useRouteMatch();
  const [repository, setrepository] = useState([]);
  const [loading, setloading] = useState(true)

  useEffect(() => {
    fetch("https://api.github.com/users/riskidwi1711/repos?")
      .then((response) => response.json())
      .then((json) => {
        setrepository(json);
        setloading(false);
      });

    return()=>{
      setrepository([])
    }
  }, []);

  return (
    <>
      <div
        id="HomePage"
        className="relative flex flex-col h-screen pl-8 text-primarycolor-light w-full bg-cover bg-my-image dark:bg-my-image2 md:w-2/3 md:rounded-r-3xl md:pl-28 "
      >
        <Header />
        <Switch>
          <Route path={match.path} exact>
            <AboutMe />
          </Route>
          <Route path={`${match.path}/aboutme`} exact>
            <AboutMe />
          </Route>
          <Route path={`${match.path}/skills`}>
            <Skills />
          </Route>
          <Route path={`${match.path}/Sertificate`}>
            <Sertificate />
          </Route>
          <Route path={`${match.path}/*`}>
            <NoMatch />
          </Route>
        </Switch>
      </div>
      <Showcase 
      repository = {repository}
      loading = {loading}
      />
    </>
  );
};

export default HomePage;