import React from "react";
import { FaSun } from "react-icons/fa";
import { HiHome, HiMail, HiNewspaper } from "react-icons/hi";
import { RiVirusLine } from "react-icons/ri";
import { Link } from "react-router-dom";  
import useDarkMode from "../hooks/useDarkMode";

function SideBar() {

   const [colorTheme, setTheme] = useDarkMode();
   
  return (
    <div className="flex flex-row md:flex-col items-center md:justify-between py-4 w-screen h-14 md:h-full md:w-16 bg-sidebarcolor-light dark:bg-primarycolor-dark md:rounded-r-3xl text-2xl fixed bottom-0">
     <div onClick={()=>setTheme(colorTheme)} className="md:relative h-12 w-14 md:rounded-r-xl rounded-b-xl md:bg-transparent ml-2 md:ml-0 md:mb-8 flex items-center justify-center">
       <FaSun fill="white"/>
     </div>
      <div className="flex flex-row md:flex-col ml-16 md:ml-0 items-center text-white justify-around h-full w-full md:h-1/4 md:justify-between ">
        <Link to="/home">
          <HiHome className="hover:text-gray-700 cursor-pointer focus:bg-gray-700" />
        </Link>
        <Link to="/blog">
          <HiNewspaper className="hover:text-gray-700 cursor-pointer  focus:bg-gray-700" />
        </Link>
        <Link to="/covid19">
        <RiVirusLine className="hover:text-gray-700 cursor-pointer  focus:bg-gray-700"/>
        </Link>
      </div>
      
    </div>
  );
}

export default SideBar;
