import React from "react";
import { BrowserRouter as Router, Switch, Route } from "react-router-dom";
import SideBar from "./component/SideBar";
import { HomePage, BlogPage, NoMatch } from "./pages";
import DetailPost from "./pages/blog/DetailPost";
import Covid from "./pages/Covid";


export default function App() {
  
  return (
    <Router>
      <div className="flex flex-col h-full min-h-screen font-poppins font-semibold bg-cover bg-pattern-light md:flex-row md:h-screen dark:bg-pattern-dark">
        <Switch>
          <Route path="/blog">
            <BlogPage />
          </Route>
          <Route path="/home">
            <HomePage />
          </Route>
          <Route path="/covid19">
            <Covid />
          </Route>
          <Route path="/post/:id">
            <DetailPost />
          </Route>
          <Route exact path="/">
            <HomePage />
          </Route>
          <Route exact path="*">
            <NoMatch />
          </Route>
        </Switch>
      </div>
      <SideBar />
    </Router>
  );
}
