import React, { useState, useEffect } from "react";
import { FaClock, FaUser } from "react-icons/fa";

const ArticleCard = (props) => {
  const [date, setdate] = useState("")

  useEffect(() => {
    getDate(props.date);
  }, [date]);

  const getDate=(x)=>{
    let y = x.split('T').shift();
    setdate(y);
  }

  return (
    <div
      onClick={() => props.history.push(`/post/${props.id}`)}
      className="m-4 bg-white dark:bg-primarycolor-dark md:shadow-md rounded-lg"
    >
      <img
        id="myImg"
        src="https://placeimg.com/640/320/tech"
        className="rounded-lg"
        alt=""
      />
      <div className="py-2 px-4">
        <p className="font-medium text-sm mb-1">{props.judul}</p>
        <div className="flex justify-between items-center text-xs font-normal">
          <span className="flex items-center">
            <FaClock className="mr-2" />
            <p>{date}</p>
          </span>
          <span className="flex items-center">
            <FaUser className="mr-2" />
            <p>{props.author}</p>
          </span>
        </div>
      </div>
    </div>
  );
};

export default ArticleCard;
