import React from "react";
import { Link, useHistory } from "react-router-dom";
import ArticleCard from "./lil-component/ArticleCard";
import Spinner from "./lil-component/Spinner";

const ArticleList = (props) => {
  let post = props.post;
  let loading = props.loading;
  const history = useHistory();
  const screenSize = props.screenSize;

  return (
    <div className="flex flex-1 dark:text-white">
      {loading ? (
        <Spinner />
      ) : (
        <div
          id="showcase"
          className="justify-start flex-col flex overflow-y-auto w-full mb-3  "
        >
          <div className="w-full p-4">
            <p className="text-lg">Blog Post</p>
            <p className="text-sm font-normal">
              Select the blog post to see the content
            </p>
          </div>
          {post.map((post, index) => {
            return screenSize.width > 768 ? (
              <Link key={index} to={`${props.url}/post/${post.id}`}>
                <ArticleCard
                  history={history}
                  key={index}
                  id={post.id}
                  judul={post.title}
                  author={post.author.displayName}
                  date={post.updated}
                />
              </Link>
            ) : (
              <ArticleCard
                history={history}
                key={index}
                id={post.id}
                judul={post.title}
                author={post.author.displayName}
                date={post.updated}
              />
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ArticleList;
