
import React, { useEffect, useState } from "react";
import Spinner from "../component/lil-component/Spinner";
import VirusCard from "../component/lil-component/VirusCard";
const Covid = () => {
  const [isloading, setisloading] = useState(true);
  const [dataCovid, setdataCovid] = useState([]);

  useEffect(() => {
    fetch("https://api.kawalcorona.com/")
      .then((res) => res.json())
      .then((json) => {
        setdataCovid(json);
        setisloading(false);
      });
  }, []);

  const myFind = (index) => {
    return index.attributes.Country_Region == "Indonesia";
  };
  const dataIdn = dataCovid.find(myFind);

  const numberWithCommas = (x) => {
    return x.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  };

  return isloading ? (
    <Spinner />
  ) : (
    <div className="flex h-full w-full justify-center items-center md:p-4 md:pl-20 text-white">
      <div className="relative bg-secondarycolor-light dark:bg-primarycolor-dark w-full md:h-full h-screen md:rounded-2xl flex flex-col items-start">
        <div className="fixed md:static px-4 mb-1 py-6 md:h-40 rounded-b-xl bg-center md:rounded-2xl bg-my-image bg-cover dark:bg-my-image2 w-full ">
          <div className="mb-4">
            <p className="md:text-2xl font-bold">
              {dataIdn.attributes.Country_Region} Corona Virus Case
            </p>
            <p className="font-normal md:text-sm text-xs ">
              Last updated at {Date(dataIdn.attributes.Last_Update)}
            </p>
          </div>
          <div className="w-full flex text-gray-700 dark:text-white">
            <VirusCard
              title={"Positive"}
              case={numberWithCommas(dataIdn.attributes.Confirmed)}
              color={"text-yellow-500"}
            />
            <VirusCard
              title={"Recovered"}
              case={numberWithCommas(dataIdn.attributes.Recovered)}
              color={"text-green-500"}
            />
            <VirusCard
              title={"Deaths"}
              case={numberWithCommas(dataIdn.attributes.Deaths)}
              color={"text-red-500"}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Covid;
