import React from 'react'
import { useHistory } from 'react-router';

function Header() {

  let history = useHistory();

    return (
        <div className="absolute top-0 font-medium text-md mt-8">
        <ul className="flex flex-row">
          <p onClick={()=>history.push("/home/aboutme")} className="mr-3 hover:text-gray-700 cursor-pointer">About Me</p>
          <p onClick={()=>history.push("/home/skills")} className="mr-3 hover:text-gray-700 cursor-pointer">Skills</p>
          <p onClick={()=>history.push("/home/sertificate")} className="mr-3 hover:text-gray-700 cursor-pointer">Contact</p>
        </ul>
      </div>
    );
}

export default Header
